   176→    let record = ComicRecord {
   177→        num: comic.num,
   178→        first_seen_utc: std::time::SystemTime::now()
   179→            .duration_since(std::time::UNIX_EPOCH)
   180→            .unwrap_or_default()
   181→            .as_secs() as i64,
   182→        image_downloaded: false,
   183→        email_sent: false,
   184→        email_sent_utc: None,
   185→    };
   186→    let json = serde_json::to_string(&record).context("failed to serialize comic record")?;
   187→    let wtx = db
   188→        .begin_write()
   189→        .context("failed to begin write transaction")?;
   190→    {
   191→        let mut table = wtx
   192→            .open_table(COMICS_TABLE)
   193→            .context("failed to open comics table")?;
   194→        table
   195→            .insert(comic.num, json.as_str())
   196→            .context("failed to insert comic record")?;
   197→    }
   198→    wtx.commit().context("failed to commit comic record")?;
   199→    Ok(())
   200→}
   201→
   202→fn record_download_success(db: &Database, num: u32) -> anyhow::Result<()> {
   203→    update_record(db, num, |r| r.image_downloaded = true)
   204→}
   205→
   206→fn record_email_success(db: &Database, num: u32) -> anyhow::Result<()> {
   207→    update_record(db, num, |r| {
   208→        r.email_sent = true;
   209→        r.email_sent_utc = Some(
   210→            std::time::SystemTime::now()
   211→                .duration_since(std::time::UNIX_EPOCH)
   212→                .unwrap_or_default()
   213→                .as_secs() as i64,
   214→        );
   215→    })
   216→}
   217→
   218→fn update_record(db: &Database, num: u32, f: impl FnOnce(&mut ComicRecord)) -> anyhow::Result<()> {
   219→    let wtx = db
   220→        .begin_write()
   221→        .context("failed to begin write transaction")?;
   222→    {
   223→        let mut table = wtx
   224→            .open_table(COMICS_TABLE)
   225→            .context("failed to open comics table")?;
   226→        let json_str = table
   227→            .get(num)
   228→            .context("failed to query comics table")?
   229→            .with_context(|| format!("comic #{num} not found in database for update"))?
   230→            .value()
   231→            .to_owned();
   232→        let mut record: ComicRecord =
   233→            serde_json::from_str(&json_str).context("failed to deserialize comic record")?;
   234→        f(&mut record);
   235→        let json = serde_json::to_string(&record).context("failed to serialize comic record")?;
   236→        table
   237→            .insert(num, json.as_str())
   238→            .context("failed to update comic record")?;
   239→    }
   240→    wtx.commit()
   241→        .context("failed to commit comic record update")?;
   242→    Ok(())
   243→}
   244→
   245→fn fetch_comic(client: &reqwest::blocking::Client) -> anyhow::Result<Comic> {
   246→    let comic = client
   247→        .get(XKCD_API_URL)
   248→        .send()
   249→        .context("failed to reach xkcd API")?
   250→        .error_for_status()
   251→        .context("xkcd API returned error status")?
   252→        .json::<Comic>()
   253→        .context("failed to parse xkcd JSON")?;
   254→    log::debug!("fetched comic #{}: {}", comic.num, comic.safe_title);
   255→    Ok(comic)
   256→}
   257→
   258→fn local_filename(comic: &Comic) -> String {
   259→    let basename = comic.img.rsplit('/').next().unwrap_or(comic.img.as_str());
   260→    format!("{}-{}", comic.num, basename)
   261→}
   262→
   263→fn download_image(client: &reqwest::blocking::Client, comic: &Comic) -> anyhow::Result<PathBuf> {
   264→    std::fs::create_dir_all(COMIC_DIR).context("failed to create comics directory")?;
   265→
   266→    let filename = local_filename(comic);
   267→    let dest = Path::new(COMIC_DIR).join(&filename);
   268→
   269→    let bytes = client
   270→        .get(&comic.img)
   271→        .send()
   272→        .context("failed to fetch comic image")?
   273→        .error_for_status()
   274→        .context("image URL returned error status")?
   275→        .bytes()
   276→        .context("failed to read image bytes")?;
   277→
   278→    std::fs::write(&dest, &bytes).with_context(|| format!("failed to write {}", dest.display()))?;
   279→
   280→    log::info!("downloaded {filename}");
   281→    Ok(dest)
   282→}
   283→
   284→fn format_date(comic: &Comic) -> anyhow::Result<String> {
   285→    let year: i32 = comic.year.parse().context("invalid year")?;
   286→    let month: u32 = comic.month.parse().context("invalid month")?;
   287→    let day: u32 = comic.day.parse().context("invalid day")?;
   288→
   289→    let date = chrono::NaiveDate::from_ymd_opt(year, month, day)
   290→        .with_context(|| format!("invalid date {year}-{month}-{day}"))?;
   291→
   292→    Ok(date.format("%a %d %b %y").to_string())
   293→}
   294→
   295→fn build_transport(config: &Config) -> anyhow::Result<SmtpTransport> {
   296→    let builder = if config.smtp_starttls {
   297→        SmtpTransport::starttls_relay(&config.smtp_server)
   298→            .context("failed to create STARTTLS transport")?
   299→    } else {
   300→        SmtpTransport::relay(&config.smtp_server)
   301→            .context("failed to create SMTP relay transport")?
   302→    };
   303→
   304→    let builder = builder.port(config.smtp_port);
   305→
   306→    let builder = match (&config.smtp_username, &config.smtp_password) {
   307→        (Some(user), Some(pass)) => {
   308→            builder.credentials(Credentials::new(user.clone(), pass.clone()))
   309→        }
   310→        _ => builder,
   311→    };
   312→
   313→    Ok(builder.build())
   314→}
   315→
   316→fn escape_html(s: &str) -> String {
   317→    let mut out = String::with_capacity(s.len());
   318→    for c in s.chars() {
   319→        match c {
   320→            '&' => out.push_str("&amp;"),
   321→            '<' => out.push_str("&lt;"),
   322→            '>' => out.push_str("&gt;"),
   323→            '"' => out.push_str("&quot;"),
   324→            '\'' => out.push_str("&#39;"),
   325→            _ => out.push(c),
   326→        }
   327→    }
   328→    out
   329→}
   330→
   331→fn send_email(
   332→    config: &Config,
   333→    comic: &Comic,
   334→    attachment_path: Option<&Path>,
   335→) -> anyhow::Result<()> {
   336→    let date_str = format_date(comic)?;
   337→    let subject = format!(
   338→        "New xkcd {}: {} from {}",
   339→        comic.num, comic.safe_title, date_str
   340→    );
   341→    let comic_url = format!("https://xkcd.com/{}/", comic.num);
   342→    let plain_text = format!("{}\n{}\n\n{}", comic.safe_title, comic_url, comic.alt);
   343→    let html_body = format!(
   344→        r#"<html><body>
   345→<h1><a href="{url}"><img title="{alt}" alt="{title}" style="display:block" src="{img}" /></a></h1>
   346→<p>{alt}</p>
   347→<br>
   348→Mailed by <a href="https://github.com/bryanhiestand/ferrous-comics">ferrous-comics</a>
   349→</body></html>"#,
   350→        url = escape_html(&comic_url),
   351→        img = escape_html(&comic.img),
   352→        title = escape_html(&comic.safe_title),
   353→        alt = escape_html(&comic.alt),
   354→    );
   355→
   356→    let alternative = MultiPart::alternative()
   357→        .singlepart(SinglePart::plain(plain_text))
   358→        .singlepart(SinglePart::html(html_body));
   359→
   360→    let body = if let Some(path) = attachment_path {
   361→        let filename = local_filename(comic);
   362→        let image_bytes = std::fs::read(path)
   363→            .with_context(|| format!("failed to read attachment {}", path.display()))?;
   364→        let content_type = match path.extension().and_then(|e| e.to_str()) {
   365→            Some("png") => ContentType::parse("image/png").unwrap(),
   366→            Some("jpg") | Some("jpeg") => ContentType::parse("image/jpeg").unwrap(),
   367→            Some("gif") => ContentType::parse("image/gif").unwrap(),
   368→            _ => ContentType::parse("application/octet-stream").unwrap(),
   369→        };
   370→        MultiPart::mixed()
   371→            .multipart(alternative)
   372→            .singlepart(Attachment::new(filename).body(image_bytes, content_type))
   373→    } else {
   374→        alternative
   375→    };
   376→
   377→    let email = Message::builder()
   378→        .from(
   379→            config
   380→                .mail_from
   381→                .parse()
   382→                .context("invalid XKCD_MAIL_FROM address")?,
   383→        )
   384→        .to(config
   385→            .mail_to
   386→            .parse()
   387→            .context("invalid XKCD_MAIL_TO address")?)
   388→        .subject(&subject)
   389→        .multipart(body)
   390→        .context("failed to build email message")?;
   391→
   392→    let transport = build_transport(config)?;
   393→    transport.send(&email).context("SMTP send failed")?;
   394→
   395→    log::info!("emailed comic #{}: {}", comic.num, comic.safe_title);
   396→    Ok(())
   397→}
   398→
   399→/// Prints all comic records in the database as newline-delimited JSON, sorted by comic number.
   400→fn cmd_dump(db: &Database) -> anyhow::Result<()> {
   401→    let rtx = db
   402→        .begin_read()
   403→        .context("failed to begin read transaction")?;
   404→    match rtx.open_table(COMICS_TABLE) {
   405→        Ok(table) => {
   406→            for entry in table.iter().context("failed to iterate comics table")? {
   407→                let (_, value) = entry.context("failed to read comics table entry")?;
   408→                println!("{}", value.value());
   409→            }
   410→            Ok(())
   411→        }
   412→        Err(redb::TableError::TableDoesNotExist(_)) => Ok(()), // empty database
   413→        Err(e) => Err(e).context("failed to open comics table"),
   414→    }
   415→}
   416→
   417→fn main() -> anyhow::Result<()> {
   418→    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or("info")).init();
   419→
   420→    let config = load_config()?;
   421→
   422→    let db = open_db(&config.db_path)?;
   423→
   424→    if std::env::args().nth(1).as_deref() == Some("dump") {
   425→        return cmd_dump(&db);
   426→    }
   427→
   428→    let client = reqwest::blocking::Client::builder()
   429→        .user_agent("ferrous-comics/0.1")
   430→        .connect_timeout(Duration::from_secs(30))
   431→        .timeout(Duration::from_secs(60))
   432→        .build()
   433→        .context("failed to build HTTP client")?;
   434→
   435→    let comic = fetch_comic(&client)?;
   436→
   437→    migrate_history_file(&db)?;
   438→
   439→    if is_seen(&db, &comic)? {
   440→        log::info!("comic #{} already seen, exiting", comic.num);
   441→        return Ok(());
   442→    }
   443→
   444→    // Mark seen immediately — prevents duplicate emails if a later step fails and cron retries.
   445→    record_first_seen(&db, &comic)?;
   446→
   447→    let image_path = if config.download {
   448→        let path = download_image(&client, &comic)?;
   449→        record_download_success(&db, comic.num)?;
   450→        Some(path)
   451→    } else {
   452→        None
   453→    };
   454→
   455→    let attachment_path = if config.mail_attachment {
   456→        image_path.as_deref()
   457→    } else {
   458→        None
   459→    };
   460→
   461→    send_email(&config, &comic, attachment_path)?;
   462→    record_email_success(&db, comic.num)?;
   463→
   464→    Ok(())
   465→}
