fn local_filename(comic: &Comic) -> String {
    let basename = comic.img.rsplit('/').next().unwrap_or(comic.img.as_str());
    format!("{}-{}", comic.num, basename)
}

fn download_image(agent: &ureq::Agent, comic: &Comic) -> anyhow::Result<PathBuf> {
