   291→    Ok(dest)
   292→}
   293→
   294→fn format_date(comic: &Comic) -> anyhow::Result<String> {
   295→    let year: i32 = comic.year.parse().context("invalid year")?;
   296→    let month: u32 = comic.month.parse().context("invalid month")?;
   297→    let day: u32 = comic.day.parse().context("invalid day")?;
   298→
   299→    let date = chrono::NaiveDate::from_ymd_opt(year, month, day)
   300→        .with_context(|| format!("invalid date {year}-{month}-{day}"))?;
   301→
   302→    Ok(date.format("%a %d %b %y").to_string())
   303→}
   304→
   305→fn build_transport(config: &Config) -> anyhow::Result<SmtpTransport> {
   306→    let builder = if config.smtp_starttls {
   307→        SmtpTransport::starttls_relay(&config.smtp_server)
   308→            .context("failed to create STARTTLS transport")?
   309→    } else {
   310→        SmtpTransport::relay(&config.smtp_server)
   311→            .context("failed to create SMTP relay transport")?
   312→    };
   313→
   314→    let builder = builder.port(config.smtp_port);
   315→
   316→    let builder = match (&config.smtp_username, &config.smtp_password) {
   317→        (Some(user), Some(pass)) => {
   318→            builder.credentials(Credentials::new(user.clone(), pass.clone()))
   319→        }
   320→        _ => builder,
   321→    };
   322→
   323→    Ok(builder.build())
   324→}
   325→
   326→fn escape_html(s: &str) -> String {
   327→    let mut out = String::with_capacity(s.len());
   328→    for c in s.chars() {
   329→        match c {
   330→            '&' => out.push_str("&amp;"),
   331→            '<' => out.push_str("&lt;"),
   332→            '>' => out.push_str("&gt;"),
   333→            '"' => out.push_str("&quot;"),
   334→            '\'' => out.push_str("&#39;"),
   335→            _ => out.push(c),
   336→        }
   337→    }
   338→    out
   339→}
   340→
   341→fn send_email(
   342→    config: &Config,
   343→    comic: &Comic,
   344→    attachment_path: Option<&Path>,
   345→) -> anyhow::Result<()> {
   346→    let date_str = format_date(comic)?;
   347→    let subject = format!(
   348→        "New xkcd {}: {} from {}",
   349→        comic.num, comic.safe_title, date_str
   350→    );
   351→    let comic_url = format!("https://xkcd.com/{}/", comic.num);
   352→    let plain_text = format!("{}\n{}\n\n{}", comic.safe_title, comic_url, comic.alt);
   353→    let html_body = format!(
   354→        r#"<html><body>
   355→<h1><a href="{url}"><img title="{alt}" alt="{title}" style="display:block" src="{img}" /></a></h1>
   356→<p>{alt}</p>
   357→<br>
   358→Mailed by <a href="https://github.com/bryanhiestand/ferrous-comics">ferrous-comics</a>
   359→</body></html>"#,
   360→        url = escape_html(&comic_url),
   361→        img = escape_html(&comic.img),
   362→        title = escape_html(&comic.safe_title),
   363→        alt = escape_html(&comic.alt),
   364→    );
   365→
   366→    let alternative = MultiPart::alternative()
   367→        .singlepart(SinglePart::plain(plain_text))
   368→        .singlepart(SinglePart::html(html_body));
   369→
   370→    let body = if let Some(path) = attachment_path {
   371→        let filename = local_filename(comic);
   372→        let image_bytes = std::fs::read(path)
   373→            .with_context(|| format!("failed to read attachment {}", path.display()))?;
   374→        let content_type = match path.extension().and_then(|e| e.to_str()) {
   375→            Some("png") => ContentType::parse("image/png").unwrap(),
   376→            Some("jpg") | Some("jpeg") => ContentType::parse("image/jpeg").unwrap(),
   377→            Some("gif") => ContentType::parse("image/gif").unwrap(),
   378→            _ => ContentType::parse("application/octet-stream").unwrap(),
   379→        };
   380→        MultiPart::mixed()
   381→            .multipart(alternative)
   382→            .singlepart(Attachment::new(filename).body(image_bytes, content_type))
   383→    } else {
   384→        alternative
   385→    };
   386→
   387→    let email = Message::builder()
   388→        .from(
   389→            config
   390→                .mail_from
   391→                .parse()
   392→                .context("invalid XKCD_MAIL_FROM address")?,
   393→        )
   394→        .to(config
   395→            .mail_to
   396→            .parse()
   397→            .context("invalid XKCD_MAIL_TO address")?)
   398→        .subject(&subject)
   399→        .multipart(body)
   400→        .context("failed to build email message")?;
   401→
   402→    let transport = build_transport(config)?;
   403→    transport.send(&email).context("SMTP send failed")?;
   404→
   405→    log::info!("emailed comic #{}: {}", comic.num, comic.safe_title);
   406→    Ok(())
   407→}
   408→
   409→/// Prints all comic records in the database as newline-delimited JSON, sorted by comic number.
   410→fn cmd_dump(db: &Database) -> anyhow::Result<()> {
   411→    let rtx = db
   412→        .begin_read()
   413→        .context("failed to begin read transaction")?;
   414→    match rtx.open_table(COMICS_TABLE) {
   415→        Ok(table) => {
   416→            for entry in table.iter().context("failed to iterate comics table")? {
   417→                let (_, value) = entry.context("failed to read comics table entry")?;
   418→                println!("{}", value.value());
   419→            }
   420→            Ok(())
   421→        }
   422→        Err(redb::TableError::TableDoesNotExist(_)) => Ok(()), // empty database
   423→        Err(e) => Err(e).context("failed to open comics table"),
   424→    }
   425→}
   426→
   427→fn main() -> anyhow::Result<()> {
   428→    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or("info")).init();
   429→
   430→    let config = load_config()?;
   431→
   432→    let db = open_db(&config.db_path)?;
   433→
   434→    if std::env::args().nth(1).as_deref() == Some("dump") {
   435→        return cmd_dump(&db);
   436→    }
   437→
   438→    let agent = ureq::AgentBuilder::new()
   439→        .timeout_connect(Duration::from_secs(30))
   440→        .timeout(Duration::from_secs(60))
   441→        .build();
   442→
   443→    let comic = fetch_comic(&agent)?;
   444→
   445→    migrate_history_file(&db)?;
   446→
   447→    if is_seen(&db, &comic)? {
   448→        log::info!("comic #{} already seen, exiting", comic.num);
   449→        return Ok(());
   450→    }
   451→
   452→    // Mark seen immediately — prevents duplicate emails if a later step fails and cron retries.
   453→    record_first_seen(&db, &comic)?;
   454→
   455→    let image_path = if config.download {
   456→        let path = download_image(&agent, &comic)?;
   457→        record_download_success(&db, comic.num)?;
   458→        Some(path)
   459→    } else {
   460→        None
   461→    };
   462→
   463→    let attachment_path = if config.mail_attachment {
   464→        image_path.as_deref()
   465→    } else {
   466→        None
   467→    };
   468→
   469→    send_email(&config, &comic, attachment_path)?;
   470→    record_email_success(&db, comic.num)?;
   471→
   472→    Ok(())
   473→}
