   100→}
   101→
   102→/// One-time migration: imports comic numbers from the legacy xkcd_history.txt into the database,
   103→/// then renames the file to xkcd_history.txt.migrated. No-op if the file does not exist.
   104→fn migrate_history_file(db: &Database) -> anyhow::Result<()> {
   105→    let path = PathBuf::from(LEGACY_HISTORY_FILE);
   106→    if !path.exists() {
   107→        return Ok(());
   108→    }
   109→
   110→    let contents = std::fs::read_to_string(&path)
   111→        .context("failed to read legacy history file for migration")?;
   112→    let nums: Vec<u32> = contents
   113→        .lines()
   114→        .filter(|l| !l.trim().is_empty())
   115→        .map(|l| l.trim().parse::<u32>())
   116→        .collect::<Result<_, _>>()
   117→        .context("invalid comic number in legacy history file")?;
   118→
   119→    let count = nums.len();
   120→    let wtx = db
   121→        .begin_write()
   122→        .context("failed to begin migration write transaction")?;
   123→    {
   124→        let mut table = wtx
   125→            .open_table(COMICS_TABLE)
   126→            .context("failed to open comics table for migration")?;
   127→        for num in nums {
   128→            if table
   129→                .get(num)
   130→                .context("failed to query comics table")?
   131→                .is_none()
   132→            {
   133→                let record = ComicRecord {
   134→                    num,
   135→                    first_seen_utc: 0, // unknown — sentinel for migrated entries
   136→                    image_downloaded: false,
   137→                    email_sent: true, // assume sent — was in history
   138→                    email_sent_utc: None,
   139→                };
   140→                let json = serde_json::to_string(&record)
   141→                    .context("failed to serialize migrated record")?;
   142→                table
   143→                    .insert(num, json.as_str())
   144→                    .context("failed to insert migrated record")?;
   145→            }
   146→        }
   147→    }
   148→    wtx.commit()
   149→        .context("failed to commit migration transaction")?;
   150→
   151→    let migrated_path = format!("{}.migrated", LEGACY_HISTORY_FILE);
   152→    std::fs::rename(&path, &migrated_path)
   153→        .context("failed to rename legacy history file after migration")?;
   154→    log::info!(
   155→        "migrated {count} comics from {LEGACY_HISTORY_FILE} to database (backup: {migrated_path})"
   156→    );
   157→
   158→    Ok(())
   159→}
