   161→fn is_seen(db: &Database, comic: &Comic) -> anyhow::Result<bool> {
   162→    let rtx = db
   163→        .begin_read()
   164→        .context("failed to begin read transaction")?;
   165→    match rtx.open_table(COMICS_TABLE) {
   166→        Ok(table) => Ok(table
   167→            .get(comic.num)
   168→            .context("failed to query comics table")?
   169→            .is_some()),
   170→        Err(redb::TableError::TableDoesNotExist(_)) => Ok(false),
   171→        Err(e) => Err(e).context("failed to open comics table"),
   172→    }
   173→}
