   175→/// Records a comic as seen immediately, before attempting download or email.
   176→/// This prevents duplicate emails if the process is re-run after a partial failure.
   177→fn record_first_seen(db: &Database, comic: &Comic) -> anyhow::Result<()> {
   178→    let record = ComicRecord {
   179→        num: comic.num,
   180→        first_seen_utc: std::time::SystemTime::now()
   181→            .duration_since(std::time::UNIX_EPOCH)
   182→            .unwrap_or_default()
   183→            .as_secs() as i64,
   184→        image_downloaded: false,
   185→        email_sent: false,
   186→        email_sent_utc: None,
   187→    };
   188→    let json = serde_json::to_string(&record).context("failed to serialize comic record")?;
   189→    let wtx = db
   190→        .begin_write()
   191→        .context("failed to begin write transaction")?;
   192→    {
   193→        let mut table = wtx
   194→            .open_table(COMICS_TABLE)
   195→            .context("failed to open comics table")?;
   196→        table
   197→            .insert(comic.num, json.as_str())
   198→            .context("failed to insert comic record")?;
   199→    }
   200→    wtx.commit().context("failed to commit comic record")?;
   201→    Ok(())
   202→}
