   220→fn update_record(db: &Database, num: u32, f: impl FnOnce(&mut ComicRecord)) -> anyhow::Result<()> {
   221→    let wtx = db
   222→        .begin_write()
   223→        .context("failed to begin write transaction")?;
   224→    {
   225→        let mut table = wtx
   226→            .open_table(COMICS_TABLE)
   227→            .context("failed to open comics table")?;
   228→        let json_str = table
   229→            .get(num)
   230→            .context("failed to query comics table")?
   231→            .with_context(|| format!("comic #{num} not found in database for update"))?
   232→            .value()
   233→            .to_owned();
   234→        let mut record: ComicRecord =
