   237→        let json = serde_json::to_string(&record).context("failed to serialize comic record")?;
   238→        table
   239→            .insert(num, json.as_str())
   240→            .context("failed to update comic record")?;
   241→    }
   242→    wtx.commit()
   243→        .context("failed to commit comic record update")?;
   244→    Ok(())
   245→}
