            Ok(v) => matches!(v.trim().to_ascii_lowercase().as_str(), "true" | "1" | "yes"),
            Err(_) => default,
        }
    }

    let config = Config {
        mail_to: env("XKCD_MAIL_TO")?,
        mail_from: env("XKCD_MAIL_FROM")?,
