    env_logger::Builder::from_env(...).init();
    let config = load_config()?;        // called dotenv, required all SMTP vars
    let db = open_db(&config.db_path)?;
    if std::env::args().nth(1).as_deref() == Some("dump") {
        return cmd_dump(&db);
    }
    // ... agent, fetch, send ...
}

fn load_config() -> anyhow::Result<Config> {
    let _ = dotenvy::dotenv();
    // ...parses XKCD_MAIL_TO, XKCD_SMTP_SERVER, etc...
    db_path: std::env::var("XKCD_DB_PATH")...
}

// After:
fn main() -> anyhow::Result<()> {
    let _ = dotenvy::dotenv();
    env_logger::Builder::from_env(...).init();

    let db_path = std::env::var("XKCD_DB_PATH")
        .map(PathBuf::from)
        .unwrap_or_else(|_| PathBuf::from("xkcd_comics.db"));
    let db = open_db(&db_path)?;

    if std::env::args().nth(1).as_deref() == Some("dump") {
        return cmd_dump(&db);
    }

    let config = load_config()?;   // no longer calls dotenv, no longer has db_path
    // ... rest unchanged ...
}

fn load_config() -> anyhow::Result<Config> {
    // dotenv call removed — now in main()
    // db_path field removed from Config struct
    // ...rest unchanged...
}
