    .from(config.mail_from.parse().context("invalid XKCD_MAIL_FROM address")?)
    .to(config.mail_to.parse().context("invalid XKCD_MAIL_TO address")?)
    .subject(&subject)
    .multipart(body)
    .context("failed to build email message")?;

// After:
