    96→/// One-time migration: imports comic numbers from the legacy xkcd_history.txt into the database,
    97→/// then renames the file to xkcd_history.txt.migrated. No-op if the file does not exist.
    98→fn migrate_history_file(db: &Database) -> anyhow::Result<()> {
    99→    let path = PathBuf::from(LEGACY_HISTORY_FILE);
   100→    if !path.exists() {
   101→        return Ok(());
   102→    }
   103→
   104→    let contents = std::fs::read_to_string(&path)
   105→        .context("failed to read legacy history file for migration")?;
   106→    let nums: Vec<u32> = contents
   107→        .lines()
   108→        .filter(|l| !l.trim().is_empty())
   109→        .map(|l| l.trim().parse::<u32>())
   110→        .collect::<Result<_, _>>()
   111→        .context("invalid comic number in legacy history file")?;
   112→
   113→    let count = nums.len();
   114→    let wtx = db
   115→        .begin_write()
   116→        .context("failed to begin migration write transaction")?;
   117→    {
   118→        let mut table = wtx
   119→            .open_table(COMICS_TABLE)
   120→            .context("failed to open comics table for migration")?;
   121→        for num in nums {
   122→            if table
   123→                .get(num)
   124→                .context("failed to query comics table")?
   125→                .is_none()
   126→            {
   127→                let record = ComicRecord {
   128→                    num,
   129→                    first_seen_utc: 0, // unknown — sentinel for migrated entries
   130→                    image_downloaded: false,
   131→                    email_sent: true, // assume sent — was in history
   132→                    email_sent_utc: None,
   133→                };
   134→                let json = serde_json::to_string(&record)
   135→                    .context("failed to serialize migrated record")?;
   136→                table
   137→                    .insert(num, json.as_str())
   138→                    .context("failed to insert migrated record")?;
   139→            }
   140→        }
   141→    }
   142→    wtx.commit()
   143→        .context("failed to commit migration transaction")?;
   144→
   145→    let migrated_path = format!("{}.migrated", LEGACY_HISTORY_FILE);
   146→    std::fs::rename(&path, &migrated_path)
   147→        .context("failed to rename legacy history file after migration")?;
   148→    log::info!(
   149→        "migrated {count} comics from {LEGACY_HISTORY_FILE} to database (backup: {migrated_path})"
   150→    );
   151→
   152→    Ok(())
   153→}
