   214→fn update_record(db: &Database, num: u32, f: impl FnOnce(&mut ComicRecord)) -> anyhow::Result<()> {
   215→    let wtx = db
   216→        .begin_write()
   217→        .context("failed to begin write transaction")?;
   218→    {
   219→        let mut table = wtx
   220→            .open_table(COMICS_TABLE)
   221→            .context("failed to open comics table")?;
   222→        let json_str = table
   223→            .get(num)
   224→            .context("failed to query comics table")?
   225→            .with_context(|| format!("comic #{num} not found in database for update"))?
   226→            .value()
   227→            .to_owned();
   228→        let mut record: ComicRecord =
   229→            serde_json::from_str(&json_str).context("failed to deserialize comic record")?;
   230→        f(&mut record);
   231→        let json = serde_json::to_string(&record).context("failed to serialize comic record")?;
   232→        table
   233→            .insert(num, json.as_str())
   234→            .context("failed to update comic record")?;
   235→    }
   236→    wtx.commit()
   237→        .context("failed to commit comic record update")?;
   238→    Ok(())
   239→}
