   320→fn escape_html(s: &str) -> String {
   321→    let mut out = String::with_capacity(s.len());
   322→    for c in s.chars() {
   323→        match c {
   324→            '&' => out.push_str("&amp;"),
   325→            '<' => out.push_str("&lt;"),
   326→            '>' => out.push_str("&gt;"),
   327→            '"' => out.push_str("&quot;"),
   328→            '\'' => out.push_str("&#39;"),
   329→            _ => out.push(c),
   330→        }
   331→    }
   332→    out
   333→}
