   335→fn send_email(
   336→    config: &Config,
   337→    comic: &Comic,
   338→    attachment_path: Option<&Path>,
   339→) -> anyhow::Result<()> {
   340→    let date_str = format_date(comic)?;
   341→    let subject = format!(
   342→        "New xkcd {}: {} from {}",
   343→        comic.num, comic.safe_title, date_str
   344→    );
   345→    let comic_url = format!("https://xkcd.com/{}/", comic.num);
   346→    let plain_text = format!("{}\n{}\n\n{}", comic.safe_title, comic_url, comic.alt);
   347→    let html_body = format!(
   348→        r#"<html><body>
   349→<h1><a href="{url}"><img title="{alt}" alt="{title}" style="display:block" src="{img}" /></a></h1>
   350→<p>{alt}</p>
   351→<br>
   352→Mailed by <a href="https://github.com/bryanhiestand/ferrous-comics">ferrous-comics</a>
   353→</body></html>"#,
   354→        url = escape_html(&comic_url),
   355→        img = escape_html(&comic.img),
   356→        title = escape_html(&comic.safe_title),
   357→        alt = escape_html(&comic.alt),
   358→    );
   359→
   360→    let alternative = MultiPart::alternative()
   361→        .singlepart(SinglePart::plain(plain_text))
   362→        .singlepart(SinglePart::html(html_body));
   363→
   364→    let body = if let Some(path) = attachment_path {
   365→        let filename = local_filename(comic);
   366→        let image_bytes = std::fs::read(path)
   367→            .with_context(|| format!("failed to read attachment {}", path.display()))?;
   368→        let content_type = match path.extension().and_then(|e| e.to_str()) {
   369→            Some("png") => ContentType::parse("image/png").unwrap(),
   370→            Some("jpg") | Some("jpeg") => ContentType::parse("image/jpeg").unwrap(),
   371→            Some("gif") => ContentType::parse("image/gif").unwrap(),
   372→            _ => ContentType::parse("application/octet-stream").unwrap(),
   373→        };
   374→        MultiPart::mixed()
   375→            .multipart(alternative)
   376→            .singlepart(Attachment::new(filename).body(image_bytes, content_type))
   377→    } else {
   378→        alternative
   379→    };
   380→
   381→    let email = Message::builder()
   382→        .from(
   383→            config
   384→                .mail_from
   385→                .parse()
   386→                .context("invalid XKCD_MAIL_FROM address")?,
   387→        )
   388→        .to(config
   389→            .mail_to
   390→            .parse()
   391→            .context("invalid XKCD_MAIL_TO address")?)
   392→        .subject(&subject)
   393→        .multipart(body)
   394→        .context("failed to build email message")?;
   395→
   396→    let transport = build_transport(config)?;
   397→    transport.send(&email).context("SMTP send failed")?;
   398→
   399→    log::info!("emailed comic #{}: {}", comic.num, comic.safe_title);
   400→    Ok(())
   401→}
